#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n;
double p[N],f[N][4];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%lf",&p[i]);
    f[0][0]=1;
    for(int i=1;i<=n;i++){
        f[i][0]=1;
        f[i][1]=p[i]*(f[i-1][1]+f[i-1][0]);
        f[i][2]=p[i]*(f[i-1][2]+2*f[i-1][1]+f[i-1][0]);
        f[i][3]=p[i]*(3*f[i-1][2]+3*f[i-1][1]+f[i-1][0])+f[i-1][3];
    }
    printf("%.1lf",f[n][3]);
    return 0;
}
